def parse_duration(s: str) -> int:
    """Parse duration string (e.g., '2h30m', '45m', '1h', '90s') and return total seconds."""
    if not s:
        raise ValueError("Duration string cannot be empty")

    total_seconds = 0
    current_num = ""
    found_unit = False

    for char in s:
        if char.isdigit():
            current_num += char
        elif char in 'hms':
            if not current_num:
                raise ValueError(f"Invalid duration format: no number before '{char}'")
            num = int(current_num)
            if char == 'h':
                total_seconds += num * 3600
            elif char == 'm':
                total_seconds += num * 60
            elif char == 's':
                total_seconds += num
            current_num = ""
            found_unit = True
        else:
            raise ValueError(f"Invalid character in duration string: '{char}'")

    if current_num:
        raise ValueError("Duration string ends with a number, missing unit (h/m/s)")

    if not found_unit:
        raise ValueError("No valid time units found in duration string")

    return total_seconds
